static inline pgr_t pgr_make(page_t *page, int err, pgno_t pgno, size_t npages, unsigned flags) {
  pgr_t r;
  r.page = page;
  r.err = err;
  r.ref.page = page;
  r.ref.cache = nullptr;
  r.ref.pgno = pgno;
  r.ref.npages = npages;
  r.ref.flags = flags;
  return r;
}

static inline pgr_t pgr_error(int err) {
  return pgr_make(nullptr, err, 0, 0, PAGE_REF_NONE);
}

static inline pgr_t pgr_empty(void) {
  return pgr_make(nullptr, MDBX_SUCCESS, 0, 0, PAGE_REF_NONE);
}

typedef struct dxb_cache_page_result {
  pgr_t page;
  size_t payload_bytes;
  bool hit;
  bool filled;
  bool tracked;
  bool submitted;
  bool completed;
} dxb_cache_page_result_t;

static inline dxb_cache_page_result_t dxb_cache_page_result(pgr_t page, size_t payload_bytes, bool hit, bool filled,
                                                            bool tracked, bool submitted, bool completed) {
  const dxb_cache_page_result_t result = {page, payload_bytes, hit, filled, tracked, submitted, completed};
  return result;
}

static inline dxb_cache_page_result_t dxb_cache_page_error(int err) {
  return dxb_cache_page_result(pgr_error(err), 0, false, false, false, false, false);
}

static inline dxb_cache_page_result_t dxb_cache_page_submitted_error(int err, bool submitted) {
  return dxb_cache_page_result(pgr_error(err), 0, false, false, false, submitted, false);
}

static inline dxb_cache_page_result_t dxb_cache_page_miss(void) {
  return dxb_cache_page_result(pgr_error(MDBX_RESULT_TRUE), 0, false, false, false, false, true);
}

static inline page_ref_t page_ref_empty(void) {
  page_ref_t ref;
  ref.page = nullptr;
  ref.cache = nullptr;
  ref.pgno = 0;
  ref.npages = 0;
  ref.flags = PAGE_REF_NONE;
  return ref;
}

static inline page_ref_t page_ref_synthetic(page_t *page) {
  page_ref_t ref;
  ref.page = page;
  ref.cache = nullptr;
  ref.pgno = page ? page->pgno : 0;
  ref.npages = page ? 1 : 0;
  ref.flags = PAGE_REF_NONE;
  return ref;
}

static inline page_ref_t page_ref_untrusted(page_t *page) {
  page_ref_t ref = page_ref_empty();
  ref.page = page;
  return ref;
}

static inline void pgr_set_ref(pgr_t *r, page_t *page, pgno_t pgno, size_t npages, unsigned flags) {
  r->page = page;
  r->ref.page = page;
  r->ref.cache = nullptr;
  r->ref.pgno = pgno;
  r->ref.npages = npages;
  r->ref.flags = flags;
}

