static inline int dxb_storage_make_data_write_io(const dxb_storage_t *storage, const dxb_byte_io_t *bytes,
                                                 dxb_data_write_io_t *io) {
  int rc = dxb_storage_byte_io_validate(bytes);
  if (unlikely(rc != MDBX_SUCCESS))
    return rc;

  const size_t pagesize = dxb_storage_pagesize(storage);
  if (unlikely((bytes->offset & (uint64_t)(pagesize - 1)) != 0 || (bytes->bytes & (pagesize - 1)) != 0))
    return MDBX_EINVAL;

  const uint64_t pgno64 = dxb_storage_bytes2pgno(storage, bytes->offset);
  const uint64_t npages64 = dxb_storage_bytes2pgno(storage, bytes->bytes);
  if (unlikely(pgno64 > (uint64_t)MAX_PAGENO + 1u || npages64 > SIZE_MAX))
    return MDBX_EINVAL;

  dxb_page_io_t pages;
  rc = dxb_storage_page_io(storage, (pgno_t)pgno64, (size_t)npages64, &pages);
  if (unlikely(rc != MDBX_SUCCESS))
    return rc;

  dxb_data_write_io_t checked;
  rc = dxb_storage_make_data_write_io_from_page(storage, &pages, &checked);
  if (unlikely(rc != MDBX_SUCCESS))
    return rc;
  if (unlikely(checked.bytes.offset != bytes->offset || checked.bytes.bytes != bytes->bytes))
    return MDBX_EINVAL;

  *io = checked;
  return MDBX_SUCCESS;
}

static inline int dxb_storage_data_write_io_validate(const dxb_storage_t *storage, const dxb_data_write_io_t *io) {
  dxb_data_write_io_t checked;
  int rc = dxb_storage_make_data_write_io(storage, &io->bytes, &checked);
  if (unlikely(rc != MDBX_SUCCESS))
    return rc;
  if (unlikely(checked.pages.pgno != io->pages.pgno || checked.pages.end_pgno != io->pages.end_pgno ||
               checked.pages.npages != io->pages.npages || checked.pages.offset != io->pages.offset ||
               checked.pages.bytes != io->pages.bytes || checked.bytes.offset != io->bytes.offset ||
               checked.bytes.bytes != io->bytes.bytes))
    return MDBX_EINVAL;
  return MDBX_SUCCESS;
}

static int dxb_storage_iov_bytes(const struct iovec *iov, size_t sgvcnt, size_t *bytes);

static inline int dxb_storage_make_write_submit_io(const dxb_storage_t *storage, const dxb_data_write_io_t *data,
                                                   const void *buffer, dxb_write_submit_io_t *io) {
  if (unlikely(!data || !buffer))
    return MDBX_EINVAL;
  int rc = dxb_storage_data_write_io_validate(storage, data);
  if (unlikely(rc != MDBX_SUCCESS))
    return rc;

  io->data = *data;
  io->buffer = buffer;
  return MDBX_SUCCESS;
}

static inline int dxb_storage_write_submit_io_validate(const dxb_storage_t *storage,
                                                       const dxb_write_submit_io_t *io) {
  if (unlikely(!io))
    return MDBX_EINVAL;
  dxb_write_submit_io_t checked;
  int rc = dxb_storage_make_write_submit_io(storage, &io->data, io->buffer, &checked);
  if (unlikely(rc != MDBX_SUCCESS))
    return rc;
  if (unlikely(checked.data.pages.pgno != io->data.pages.pgno ||
               checked.data.pages.end_pgno != io->data.pages.end_pgno ||
               checked.data.pages.npages != io->data.pages.npages ||
               checked.data.pages.offset != io->data.pages.offset ||
               checked.data.pages.bytes != io->data.pages.bytes ||
               checked.data.bytes.offset != io->data.bytes.offset ||
               checked.data.bytes.bytes != io->data.bytes.bytes || checked.buffer != io->buffer))
    return MDBX_EINVAL;
  return MDBX_SUCCESS;
}

static inline int dxb_storage_make_writev_submit_io(const dxb_storage_t *storage, const dxb_data_write_io_t *data,
                                                    struct iovec *iov, size_t sgvcnt,
                                                    dxb_writev_submit_io_t *io) {
  if (unlikely(!data || !iov || !sgvcnt))
    return MDBX_EINVAL;
  int rc = dxb_storage_data_write_io_validate(storage, data);
  if (unlikely(rc != MDBX_SUCCESS))
    return rc;
  size_t bytes;
  rc = dxb_storage_iov_bytes(iov, sgvcnt, &bytes);
  if (unlikely(rc != MDBX_SUCCESS))
    return rc;
  if (unlikely(bytes != data->bytes.bytes))
    return MDBX_EINVAL;

  io->data = *data;
  io->iov = iov;
  io->sgvcnt = sgvcnt;
  return MDBX_SUCCESS;
}

static inline int dxb_storage_writev_submit_io_validate(const dxb_storage_t *storage,
                                                        const dxb_writev_submit_io_t *io) {
  if (unlikely(!io))
    return MDBX_EINVAL;
  dxb_writev_submit_io_t checked;
  int rc = dxb_storage_make_writev_submit_io(storage, &io->data, io->iov, io->sgvcnt, &checked);
  if (unlikely(rc != MDBX_SUCCESS))
    return rc;
  if (unlikely(checked.data.pages.pgno != io->data.pages.pgno ||
               checked.data.pages.end_pgno != io->data.pages.end_pgno ||
               checked.data.pages.npages != io->data.pages.npages ||
               checked.data.pages.offset != io->data.pages.offset ||
               checked.data.pages.bytes != io->data.pages.bytes ||
               checked.data.bytes.offset != io->data.bytes.offset ||
               checked.data.bytes.bytes != io->data.bytes.bytes || checked.iov != io->iov ||
               checked.sgvcnt != io->sgvcnt))
    return MDBX_EINVAL;
  return MDBX_SUCCESS;
}

static inline int dxb_data_write_io_validate_queued(const dxb_data_write_io_t *io, size_t bytes) {
  if (unlikely(!io))
    return MDBX_EINVAL;

  int rc = dxb_storage_byte_io_validate(&io->bytes);
  if (unlikely(rc != MDBX_SUCCESS))
    return rc;
  if (unlikely(bytes != io->bytes.bytes || io->pages.npages == 0 ||
               io->pages.npages > (size_t)(UINT32_MAX - io->pages.pgno) ||
               io->pages.end_pgno != io->pages.pgno + (uint32_t)io->pages.npages ||
               io->pages.offset != io->bytes.offset || io->pages.bytes != io->bytes.bytes ||
               io->pages.bytes % io->pages.npages != 0))
    return MDBX_EINVAL;

  const size_t pagesize = io->pages.bytes / io->pages.npages;
  if (unlikely(!is_powerof2(pagesize) || pagesize < MDBX_MIN_PAGESIZE || pagesize > MDBX_MAX_PAGESIZE))
    return MDBX_EINVAL;

  return MDBX_SUCCESS;
}

static inline int dxb_storage_queued_data_write_io_validate(const dxb_storage_t *storage,
                                                           const dxb_data_write_io_t *io) {
  if (unlikely(!io))
    return MDBX_EINVAL;

  int rc = dxb_storage_data_write_io_validate(storage, io);
  if (unlikely(rc != MDBX_SUCCESS))
    return rc;
  return dxb_data_write_io_validate_queued(io, io->bytes.bytes);
}

static unsigned osal_ioring_write_items(const osal_ioring_t *ior);
