static void osal_ioring_write_linux_uring(osal_ioring_t *ior, const dxb_queued_write_io_t *io,
                                          osal_ioring_write_result_t *r) {
  if (unlikely(!osal_ioring_linux_uring_ready(ior))) {
    r->err = MDBX_EINVAL;
    return;
  }
  if (unlikely(osal_ioring_linux_uring_should_fallback_to_sync())) {
    osal_ioring_write_sync(ior, io, r);
    return;
  }
  r->err = osal_ioring_linux_uring_lock(ior);
  if (unlikely(r->err != MDBX_SUCCESS))
    return;

  ior_item_t *item = ior->pool;
  while (item <= ior->last) {
    const uint32_t sq_entries = *ior->linux_uring_sq_entries;
    const uint32_t sq_mask = *ior->linux_uring_sq_mask;
    uint32_t head = osal_ioring_linux_load(ior->linux_uring_sq_head);
    uint32_t tail = osal_ioring_linux_load(ior->linux_uring_sq_tail);
    if (unlikely(tail - head > sq_entries)) {
      r->err = MDBX_PROBLEM;
      goto bailout;
    }
    unsigned space = sq_entries - (tail - head);
    if (unlikely(!space)) {
      const int rc = osal_ioring_linux_enter(ior, 0, 0, 0);
      if (unlikely(rc < 0)) {
        r->err = -rc;
        goto bailout;
      }
      head = osal_ioring_linux_load(ior->linux_uring_sq_head);
      tail = osal_ioring_linux_load(ior->linux_uring_sq_tail);
      space = likely(tail - head <= sq_entries) ? sq_entries - (tail - head) : 0;
      if (unlikely(!space)) {
        r->err = EBUSY;
        goto bailout;
      }
    }

    unsigned prepared = 0;
    while (prepared < space && item <= ior->last) {
      const uint32_t index = tail & sq_mask;
      struct io_uring_sqe *const sqe = &ior->linux_uring_sqes[index];
      const size_t sgvcnt = osal_ioring_linux_uring_prep_item(ior, io, r, item, sqe);
      if (unlikely(r->err != MDBX_SUCCESS))
        break;
      ior->linux_uring_sq_array[index] = index;
      ++tail;
      ++prepared;
      item = ior_next(item, sgvcnt);
    }

    if (prepared) {
      osal_ioring_linux_store(ior->linux_uring_sq_tail, tail);
      unsigned submitted = 0;
      const int submit_err = osal_ioring_linux_uring_submit(ior, prepared, &submitted);
      const int drain_err = submitted ? osal_ioring_linux_uring_drain(ior, submitted) : MDBX_SUCCESS;
      if (unlikely(submit_err != MDBX_SUCCESS)) {
        r->err = submit_err;
        goto bailout;
      }
      if (unlikely(submitted != prepared)) {
        r->err = MDBX_EIO;
        goto bailout;
      }
      if (unlikely(drain_err != MDBX_SUCCESS)) {
        r->err = drain_err;
        goto bailout;
      }
    }
    if (unlikely(r->err != MDBX_SUCCESS))
      goto bailout;
    if (unlikely(!prepared)) {
      r->err = MDBX_PROBLEM;
      goto bailout;
    }
  }

bailout:
  r->err = osal_ioring_linux_uring_unlock(ior, r->err);
}
#endif /* MDBX_HAVE_LINUX_IO_URING */
#endif /* !Windows */

osal_ioring_write_result_t osal_ioring_write(osal_ioring_t *ior, const dxb_queued_write_io_t *io) {
  osal_ioring_write_result_t r = {MDBX_SUCCESS, 0, 0, 0, 0, osal_ioring_backend_unset, false};
  if (unlikely(!ior)) {
    r.err = MDBX_EINVAL;
    return r;
  }
  r.backend = ior->backend;
  r.async_backend = osal_ioring_backend_is_async(ior->backend);
  r.err = dxb_queued_write_io_validate(io);
  if (unlikely(r.err != MDBX_SUCCESS))
    return r;
  if (unlikely(osal_ioring_used(ior) != io->used_slots)) {
    r.err = MDBX_EINVAL;
    return r;
  }
  if (unlikely(osal_ioring_write_items(ior) != io->write_items)) {
    r.err = MDBX_EINVAL;
    return r;
  }
  if (unlikely(osal_ioring_payload_bytes(ior) != io->payload_bytes)) {
    r.err = MDBX_EINVAL;
    return r;
  }

#if defined(_WIN32) || defined(_WIN64)
  const mdbx_filehandle_t fd = io->fd;
  HANDLE *const end_wait_for = ior->event_pool + ior->allocated +
                               /* был выделен один дополнительный элемент для async_done */ 1;
  HANDLE *wait_for = end_wait_for;
  LONG async_started = 0;
  for (ior_item_t *item = ior->pool; item <= ior->last;) {
    item->ov.Internal = STATUS_PENDING;
    size_t i = 1, bytes = item->single.iov_len - ior_WriteFile_flag;
    r.wops += 1;
    if (bytes & ior_WriteFile_flag) {
      ASSERT(ior->overlapped_fd && fd == ior->overlapped_fd);
      bytes = ior->pagesize;
      /* Zap: Reading invalid data from 'item->sgv' */
      MDBX_SUPPRESS_GOOFY_MSVC_ANALYZER(6385);
      while (item->sgv[i].Buffer) {
        bytes += ior->pagesize;
        ++i;
      }
      ASSERT(bytes < MAX_WRITE);
      r.err = osal_ioring_item_io_validate(item, bytes);
      if (unlikely(r.err != MDBX_SUCCESS))
        goto bailout_rc;
      item->ov.hEvent = ior_get_event(ior);
      if (unlikely(!item->ov.hEvent)) {
      bailout_geterr:
        r.err = GetLastError();
      bailout_rc:
        ASSERT(r.err != MDBX_SUCCESS);
        CancelIo(fd);
        return r;
      }
      if (WriteFileGather(fd, item->sgv, (DWORD)bytes, nullptr, &item->ov)) {
        ASSERT(item->ov.Internal == 0 && WaitForSingleObject(item->ov.hEvent, 0) == WAIT_OBJECT_0);
        ior_put_event(ior, item->ov.hEvent);
        item->ov.hEvent = 0;
      } else {
        r.err = (int)GetLastError();
        if (unlikely(r.err != ERROR_IO_PENDING)) {
          void *data = Ptr64ToPtr(item->sgv[0].Buffer);
          ERROR("%s: fd %p, item %p (%zu), addr %p pgno %u, bytes %zu,"
                " offset %" PRId64 ", err %d",
                "WriteFileGather", fd, __Wpedantic_format_voidptr(item), item - ior->pool, data, ((page_t *)data)->pgno,
                bytes, item->ov.Offset + ((uint64_t)item->ov.OffsetHigh << 32), r.err);
          goto bailout_rc;
        }
        ASSERT(wait_for > ior->event_pool + ior->event_stack);
        *--wait_for = item->ov.hEvent;
      }
    } else if (fd == ior->overlapped_fd) {
      ASSERT(bytes < MAX_WRITE);
      r.err = osal_ioring_item_io_validate(item, bytes);
      if (unlikely(r.err != MDBX_SUCCESS))
        goto bailout_rc;
    retry:
      item->ov.hEvent = ior;
      if (WriteFileEx(fd, item->single.iov_base, (DWORD)bytes, &item->ov, ior_wocr)) {
        async_started += 1;
      } else {
        r.err = (int)GetLastError();
        switch (r.err) {
        default:
          ERROR("%s: fd %p, item %p (%zu), addr %p pgno %u, bytes %zu,"
                " offset %" PRId64 ", err %d",
                "WriteFileEx", fd, __Wpedantic_format_voidptr(item), item - ior->pool, item->single.iov_base,
                ((page_t *)item->single.iov_base)->pgno, bytes, item->ov.Offset + ((uint64_t)item->ov.OffsetHigh << 32),
                r.err);
          goto bailout_rc;
        case ERROR_NOT_FOUND:
        case ERROR_USER_MAPPED_FILE:
        case ERROR_LOCK_VIOLATION:
          WARNING("%s: fd %p, item %p (%zu), addr %p pgno %u, bytes %zu,"
                  " offset %" PRId64 ", err %d",
                  "WriteFileEx", fd, __Wpedantic_format_voidptr(item), item - ior->pool, item->single.iov_base,
                  ((page_t *)item->single.iov_base)->pgno, bytes,
                  item->ov.Offset + ((uint64_t)item->ov.OffsetHigh << 32), r.err);
          SleepEx(0, true);
          goto retry;
        case ERROR_INVALID_USER_BUFFER:
        case ERROR_NOT_ENOUGH_MEMORY:
          if (SleepEx(0, true) == WAIT_IO_COMPLETION)
            goto retry;
          goto bailout_rc;
        case ERROR_IO_PENDING:
          async_started += 1;
        }
      }
    } else {
      ASSERT(bytes < MAX_WRITE);
      r.err = osal_ioring_item_io_validate(item, bytes);
      if (unlikely(r.err != MDBX_SUCCESS))
        goto bailout_rc;
      DWORD written = 0;
      if (!WriteFile(fd, item->single.iov_base, (DWORD)bytes, &written, &item->ov)) {
        r.err = (int)GetLastError();
        ERROR("%s: fd %p, item %p (%zu), addr %p pgno %u, bytes %zu,"
              " offset %" PRId64 ", err %d",
              "WriteFile", fd, __Wpedantic_format_voidptr(item), item - ior->pool, item->single.iov_base,
              ((page_t *)item->single.iov_base)->pgno, bytes, item->ov.Offset + ((uint64_t)item->ov.OffsetHigh << 32),
              r.err);
        goto bailout_rc;
      } else if (unlikely(written != bytes)) {
        r.err = ERROR_WRITE_FAULT;
        goto bailout_rc;
      }
    }
    item = ior_next(item, i);
  }

  ASSERT(ior->async_waiting > ior->async_completed && ior->async_waiting == INT_MAX);
  ior->async_waiting = async_started;
  if (async_started > ior->async_completed && end_wait_for == wait_for) {
    ASSERT(wait_for > ior->event_pool + ior->event_stack);
    *--wait_for = ior->async_done;
  }

  const size_t pending_count = end_wait_for - wait_for;
  if (pending_count) {
    /* Ждем до MAXIMUM_WAIT_OBJECTS (64) последних хендлов, а после избирательно
     * ждем посредством GetOverlappedResult(), если какие-то более ранние
     * элементы еще не завершены. В целом, так получается меньше системных
     * вызовов, т.е. меньше накладных расходов. Однако, не факт что эта экономия
     * не будет перекрыта неэффективностью реализации
     * WaitForMultipleObjectsEx(), но тогда это проблемы на стороне M$. */
    DWORD madness;
    do
      madness = WaitForMultipleObjectsEx(
          (pending_count < MAXIMUM_WAIT_OBJECTS) ? (DWORD)pending_count : MAXIMUM_WAIT_OBJECTS, wait_for, true,
          /* сутки */ 86400000ul, true);
    while (madness == WAIT_IO_COMPLETION);
    STATIC_ASSERT(WAIT_OBJECT_0 == 0);
    if (/* madness >= WAIT_OBJECT_0 && */
        madness < WAIT_OBJECT_0 + MAXIMUM_WAIT_OBJECTS)
      r.err = MDBX_SUCCESS;
    else if (madness >= WAIT_ABANDONED_0 && madness < WAIT_ABANDONED_0 + MAXIMUM_WAIT_OBJECTS) {
      r.err = ERROR_ABANDONED_WAIT_0;
      goto bailout_rc;
    } else if (madness == WAIT_TIMEOUT) {
      r.err = WAIT_TIMEOUT;
      goto bailout_rc;
    } else {
      r.err = /* madness == WAIT_FAILED */ MDBX_PROBLEM;
      goto bailout_rc;
    }

    ASSERT(ior->async_waiting == ior->async_completed);
    for (ior_item_t *item = ior->pool; item <= ior->last;) {
      size_t i = 1, bytes = item->single.iov_len - ior_WriteFile_flag;
      void *data = item->single.iov_base;
      if (bytes & ior_WriteFile_flag) {
        data = Ptr64ToPtr(item->sgv[0].Buffer);
        bytes = ior->pagesize;
        /* Zap: Reading invalid data from 'item->sgv' */
        MDBX_SUPPRESS_GOOFY_MSVC_ANALYZER(6385);
        while (item->sgv[i].Buffer) {
          bytes += ior->pagesize;
          ++i;
        }
        if (!HasOverlappedIoCompleted(&item->ov)) {
          DWORD written = 0;
          if (unlikely(!GetOverlappedResult(fd, &item->ov, &written, true))) {
            ERROR("%s: item %p (%zu), addr %p pgno %u, bytes %zu,"
                  " offset %" PRId64 ", err %d",
                  "GetOverlappedResult", __Wpedantic_format_voidptr(item), item - ior->pool, data,
                  ((page_t *)data)->pgno, bytes, item->ov.Offset + ((uint64_t)item->ov.OffsetHigh << 32),
                  (int)GetLastError());
            goto bailout_geterr;
          }
          ASSERT(MDBX_SUCCESS == item->ov.Internal);
          ASSERT(written == item->ov.InternalHigh);
        }
      } else {
        ASSERT(HasOverlappedIoCompleted(&item->ov));
      }
      ASSERT(item->ov.Internal != ERROR_IO_PENDING);
      if (unlikely(item->ov.Internal != MDBX_SUCCESS)) {
        DWORD written = 0;
        r.err = (int)item->ov.Internal;
        if ((r.err & 0x80000000) && GetOverlappedResult(nullptr, &item->ov, &written, true))
          r.err = (int)GetLastError();
        ERROR("%s: item %p (%zu), addr %p pgno %u, bytes %zu,"
              " offset %" PRId64 ", err %d",
              "Result", __Wpedantic_format_voidptr(item), item - ior->pool, data, ((page_t *)data)->pgno, bytes,
              item->ov.Offset + ((uint64_t)item->ov.OffsetHigh << 32), (int)GetLastError());
        goto bailout_rc;
      }
      if (unlikely(item->ov.InternalHigh != bytes)) {
        r.err = ERROR_WRITE_FAULT;
        goto bailout_rc;
      }
      item = ior_next(item, i);
    }
    ASSERT(ior->async_waiting == ior->async_completed);
  } else {
    ASSERT(r.err == MDBX_SUCCESS);
  }
  ASSERT(ior->async_waiting == ior->async_completed);

#else
  switch (ior->backend) {
  case osal_ioring_backend_sync:
    osal_ioring_write_sync(ior, io, &r);
    break;
  case osal_ioring_backend_linux_uring:
#if MDBX_HAVE_LINUX_IO_URING
    osal_ioring_write_linux_uring(ior, io, &r);
#else
    r.err = MDBX_ENOSYS;
#endif /* MDBX_HAVE_LINUX_IO_URING */
    break;
  case osal_ioring_backend_unset:
  case osal_ioring_backend_windows_overlapped:
  default:
    r.err = MDBX_EINVAL;
    break;
  }

#endif /* !Windows */
  if (likely(r.err == MDBX_SUCCESS)) {
    r.write_items = io->write_items;
    r.used_slots = io->used_slots;
    r.payload_bytes = io->payload_bytes;
  }
  return r;
}

int osal_ioring_pread(osal_ioring_t *ior, mdbx_filehandle_t fd, void *buf, size_t bytes, uint64_t offset) {
#if MDBX_HAVE_LINUX_IO_URING
  if (likely(ior && ior->backend == osal_ioring_backend_linux_uring &&
             osal_ioring_linux_uring_ready(ior)))
    return osal_ioring_linux_uring_read(ior, fd, buf, bytes, offset);
#else
  (void)ior;
#endif /* MDBX_HAVE_LINUX_IO_URING */
  return osal_pread(fd, buf, bytes, offset);
}

int osal_ioring_pwrite(osal_ioring_t *ior, mdbx_filehandle_t fd, const void *buf, size_t bytes, uint64_t offset) {
#if MDBX_HAVE_LINUX_IO_URING
  if (likely(ior && ior->backend == osal_ioring_backend_linux_uring &&
             osal_ioring_linux_uring_ready(ior) && bytes <= INT32_MAX)) {
    const int err = osal_ioring_linux_uring_write(ior, fd, buf, bytes, offset);
    if (likely(err == MDBX_SUCCESS || (err != MDBX_EINVAL && err != MDBX_ENOSYS && err != EOPNOTSUPP)))
      return err;
  }
#else
  (void)ior;
#endif /* MDBX_HAVE_LINUX_IO_URING */
  return osal_pwrite(fd, buf, bytes, offset);
}

